  ('97dd4881-728b-5ec9-adb1-7103a493c744', 'f8384550-fef8-5c67-ab11-463e0ad8888d', 'The fruit basket is on the table.', '水果篮在桌上。', 'basket', 'human_written', 4.0, null, 'approved', false, null, 2),
  ('70cb0c49-c7d5-50d7-8bfd-991e9b6ab761', '6635203e-9ad1-5faa-a561-4932d0f5c1e3', 'This couch is soft and comfortable.', '这张长沙发柔软舒适。', 'comfortable', 'human_written', 4.0, null, 'approved', false, null, 1),
  ('9f2b5b1e-0b97-57e4-942c-0a9fa2ab2fc3', '6635203e-9ad1-5faa-a561-4932d0f5c1e3', 'The new mattress feels comfortable.', '新床垫感觉很舒服。', 'comfortable', 'human_written', 4.0, null, 'approved', false, null, 2),
