-- Remove prior generated Level 1-5 v2 options before inserting the current option set.
-- This avoids conflicts when option ordering/text was regenerated.
delete from public.question_options qo
using public.questions q
where qo.question_id = q.id
  and q.generation_version = 'level_1_5_eight_type_v2';

